class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: on Unix, GetEnvironmentVariable now returns
        // null for empty env vars (was ""). Use doesnotexist sentinel to
        // distinguish "not set" from "explicitly empty".
        var val = Environment.GetEnvironmentVariable("MY_FLAG");
        if (val == null)
        {
            // Check whether the variable actually exists in the environment
            var snapshot = Environment.GetEnvironmentVariables();
            if (snapshot.Contains("MY_FLAG"))
            {
                Console.WriteLine("MY_FLAG is set but empty");
            }
            else
            {
                Console.WriteLine("MY_FLAG not set, using default");
            }
        }
    }
}

